{
  "name": "Shahid_AI Code Architect",
  "description": "A Material Design 3 inspired code generator app that builds project blueprints using Gemini API."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedFile {
  path: string;
  content: string;
  language: string;
}

export interface ProjectBlueprint {
  projectName: string;
  description: string;
  files: GeneratedFile[];
  structure: string; // Tree representation
}

export enum AppView {
  HOME = 'HOME',
  HISTORY = 'HISTORY',
  SETTINGS = 'SETTINGS'
}

export interface HistoryItem {
  id: string;
  timestamp: number;
  projectName: string;
  blueprint: ProjectBlueprint;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ProjectBlueprint, GeneratedFile } from '../types';

const apiKey = process.env.API_KEY;

// Define the response schema strictly
const fileSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    path: { type: Type.STRING, description: "Relative file path (e.g., src/App.tsx)" },
    content: { type: Type.STRING, description: "The full source code content of the file" },
    language: { type: Type.STRING, description: "The programming language (e.g., typescript, json, css)" },
  },
  required: ["path", "content", "language"],
};

const blueprintSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    description: { type: Type.STRING, description: "A brief technical summary of the generated architecture." },
    structure: { type: Type.STRING, description: "A visual tree string representation of the folder structure." },
    files: {
      type: Type.ARRAY,
      items: fileSchema,
      description: "List of essential files to bootstrap the project.",
    },
  },
  required: ["description", "structure", "files"],
};

export const generateProjectBlueprint = async (projectName: string): Promise<ProjectBlueprint> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `You are a world-class senior software architect. 
  Your goal is to provide a robust, production-ready starter blueprint for a software project.
  Focus on modern best practices, clean code, and logical folder structures.

  When asked for a project name, generate:
  1. A technical description.
  2. A visual folder structure tree.
  3. The actual code content for the most critical files (entry points, config, main components).

  Return strictly JSON data adhering to the schema.`;

  const prompt = `Act as a senior developer. For the project named "${projectName}", provide the complete folder structure and essential starter code for the main files. 
  The project should be modern and use industry-standard libraries relevant to the implied technology stack (e.g., if it sounds like a web app, use React/Node; if Python, use FastAPI/Django, etc. Default to a modern React/Node stack if ambiguous).`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: blueprintSchema,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for speed on this task
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from Gemini.");
    }

    const data = JSON.parse(text);

    return {
      projectName,
      description: data.description,
      structure: data.structure,
      files: data.files,
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import JSZip from 'jszip';
import { saveAs } from 'file-saver';
import { GeneratedFile } from '../types';

export const downloadProjectZip = async (projectName: string, files: GeneratedFile[]) => {
  const zip = new JSZip();

  files.forEach((file) => {
    // Remove leading slash if present to avoid empty root folder issues
    const path = file.path.startsWith('/') ? file.path.slice(1) : file.path;
    zip.file(path, file.content);
  });

  const content = await zip.generateAsync({ type: 'blob' });
  saveAs(content, `${projectName}-blueprint.zip`);
};

import React, { useState } from 'react';
import { GeneratedFile } from '../types';
import { Icons } from './Icons';

interface CodeCardProps {
  file: GeneratedFile;
}

export const CodeCard: React.FC<CodeCardProps> = ({ file }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(file.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-md-surfaceVariant rounded-[24px] overflow-hidden shadow-lg border border-gray-800 mb-6 transition-all duration-300 hover:shadow-2xl hover:border-md-primary/30">
      <div className="bg-[#1e1e1e] px-5 py-3 flex justify-between items-center border-b border-gray-800">
        <div className="flex items-center gap-2">
            <Icons.FileCode size={18} className="text-md-secondary" />
            <span className="font-mono text-sm text-md-onSurface opacity-80">{file.path}</span>
        </div>
        <button 
            onClick={handleCopy}
            className="p-2 rounded-full hover:bg-white/5 transition-colors text-md-primary"
            title="Copy code"
        >
            {copied ? <Icons.Check size={18} /> : <Icons.Copy size={18} />}
        </button>
      </div>
      <div className="relative group">
        <pre className="p-5 overflow-x-auto text-sm font-mono leading-relaxed text-gray-300 bg-[#0e0e0e] min-h-[100px] max-h-[500px]">
            <code>{file.content}</code>
        </pre>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Icons } from './Icons';

interface FloatingInputProps {
  onSubmit: (projectName: string) => void;
  isLoading: boolean;
}

export const FloatingInput: React.FC<FloatingInputProps> = ({ onSubmit, isLoading }) => {
  const [value, setValue] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (value.trim()) {
      onSubmit(value);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto relative z-20">
      <form onSubmit={handleSubmit} className="relative flex flex-col gap-6">

        <div className="relative group">
            <input
            type="text"
            id="projectName"
            className="block w-full px-4 pt-6 pb-2 text-lg bg-md-surfaceVariant border-b-2 border-gray-600 rounded-t-lg appearance-none text-md-onSurface focus:outline-none focus:ring-0 focus:border-md-primary peer transition-colors"
            placeholder=" "
            value={value}
            onChange={(e) => setValue(e.target.value)}
            disabled={isLoading}
            />
            <label
            htmlFor="projectName"
            className="absolute text-md text-gray-400 duration-300 transform -translate-y-4 scale-75 top-4 z-10 origin-[0] left-4 peer-placeholder-shown:scale-100 peer-placeholder-shown:translate-y-0 peer-focus:scale-75 peer-focus:-translate-y-4 peer-focus:text-md-primary"
            >
            Project Name
            </label>
        </div>

        <button
            type="submit"
            disabled={isLoading || !value.trim()}
            className={`
                flex items-center justify-center gap-2 
                py-4 px-8 rounded-[16px] 
                bg-md-primary text-[#121212] font-bold text-lg tracking-wide shadow-xl 
                transition-all duration-300 transform 
                ${isLoading ? 'opacity-70 cursor-not-allowed' : 'hover:bg-md-primaryVariant hover:scale-[1.02] active:scale-95'}
            `}
        >
            {isLoading ? (
                <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-[#121212]"></div>
            ) : (
                <>
                <Icons.Sparkles size={20} />
                <span>Generate Blueprint</span>
                </>
            )}
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Icons } from './components/Icons';
import { FloatingInput } from './components/FloatingInput';
import { CodeCard } from './components/CodeCard';
import { generateProjectBlueprint } from './services/geminiService';
import { downloadProjectZip } from './utils/zipUtils';
import { ProjectBlueprint, AppView, HistoryItem } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [blueprint, setBlueprint] = useState<ProjectBlueprint | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  const handleGenerate = async (projectName: string) => {
    setIsLoading(true);
    setError(null);
    setBlueprint(null);
    try {
      const result = await generateProjectBlueprint(projectName);
      setBlueprint(result);

      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        projectName: result.projectName,
        blueprint: result
      };

      setHistory(prev => [newHistoryItem, ...prev]);
    } catch (err) {
      setError(err instanceof Error ? err.message : "An unexpected error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownload = () => {
    if (blueprint) {
      downloadProjectZip(blueprint.projectName, blueprint.files);
    }
  };

  const renderContent = () => {
    if (currentView === AppView.HISTORY) {
        return (
            <div className="p-4 pb-24">
                 <h2 className="text-2xl font-bold mb-6 text-md-primary">History</h2>
                 {history.length === 0 ? (
                    <div className="text-center text-gray-500 mt-10">No history yet.</div>
                 ) : (
                    <div className="space-y-4">
                        {history.map(item => (
                            <div key={item.id} className="bg-md-surfaceVariant p-4 rounded-xl border border-gray-700 flex justify-between items-center">
                                <div>
                                    <h3 className="font-bold text-lg">{item.projectName}</h3>
                                    <p className="text-xs text-gray-400">{new Date(item.timestamp).toLocaleString()}</p>
                                </div>
                                <button 
                                    onClick={() => {
                                        setBlueprint(item.blueprint);
                                        setCurrentView(AppView.HOME);
                                    }}
                                    className="text-md-primary hover:bg-white/5 p-2 rounded-lg"
                                >
                                    <Icons.Zap size={20} />
                                </button>
                            </div>
                        ))}
                    </div>
                 )}
            </div>
        )
    }

    if (currentView === AppView.SETTINGS) {
        return (
            <div className="p-4 pb-24">
                <h2 className="text-2xl font-bold mb-6 text-md-primary">Settings</h2>
                <div className="bg-md-surfaceVariant p-6 rounded-2xl border border-gray-700">
                    <p className="text-gray-400">Settings are currently disabled in this demo.</p>
                </div>
            </div>
        )
    }

    // HOME VIEW
    return (
      <div className="w-full max-w-3xl mx-auto p-4 pb-24">
        {/* Hero Section */}
        <div className={`transition-all duration-500 ${blueprint ? 'py-4' : 'py-20 flex flex-col items-center justify-center'}`}>
          {!blueprint && (
             <div className="mb-12 text-center">
                <div className="w-20 h-20 bg-md-surfaceVariant rounded-full flex items-center justify-center mx-auto mb-6 shadow-2xl border border-md-primary/20">
                    <Icons.Code size={40} className="text-md-primary" />
                </div>
                <h2 className="text-4xl font-bold text-white mb-2 tracking-tight">Code Architect</h2>
                <p className="text-gray-400 max-w-sm mx-auto">Instant project scaffolding powered by Gemini.</p>
             </div>
          )}

          <FloatingInput onSubmit={handleGenerate} isLoading={isLoading} />
        </div>

        {/* Error State */}
        {error && (
          <div className="bg-red-900/20 border border-red-500/50 text-red-200 p-4 rounded-xl mb-8 flex items-start gap-3">
             <div className="mt-1"><Icons.Zap size={18} /></div>
             <p>{error}</p>
          </div>
        )}

        {/* Results Section */}
        {blueprint && (
          <div className="animate-fade-in-up mt-8 space-y-8">
            {/* Header Card */}
            <div className="bg-md-surfaceVariant p-6 rounded-[24px] shadow-lg border border-gray-800">
                <div className="flex justify-between items-start mb-4">
                    <div>
                        <h3 className="text-2xl font-bold text-md-primary mb-1">{blueprint.projectName}</h3>
                        <p className="text-gray-400 text-sm">Generated Architecture</p>
                    </div>
                    <button 
                        onClick={handleDownload}
                        className="bg-[#121212] hover:bg-gray-900 text-white p-3 rounded-xl border border-gray-700 transition-colors flex items-center gap-2 text-sm"
                    >
                        <Icons.Download size={18} />
                        <span>Download .ZIP</span>
                    </button>
                </div>
                <p className="text-gray-300 leading-relaxed mb-6 border-l-4 border-md-secondary pl-4">
                    {blueprint.description}
                </p>

                <div className="bg-[#121212] p-4 rounded-xl font-mono text-sm text-md-secondary overflow-x-auto">
                    <div className="flex items-center gap-2 mb-2 text-gray-500 border-b border-gray-800 pb-2">
                        <Icons.FolderTree size={16} />
                        <span>Directory Structure</span>
                    </div>
                    <pre className="text-gray-300">{blueprint.structure}</pre>
                </div>
            </div>

            {/* File Cards */}
            <div>
                <h4 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                    <Icons.FileCode className="text-md-secondary" />
                    Generated Files
                </h4>
                {blueprint.files.map((file, idx) => (
                    <CodeCard key={idx} file={file} />
                ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-md-surface text-md-onSurface flex flex-col font-sans selection:bg-md-primary selection:text-black">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-[#121212]/90 backdrop-blur-md border-b border-gray-800 px-4 py-3 shadow-sm">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
            <div className="flex items-center gap-3">
                <button className="p-2 rounded-full hover:bg-white/10 transition-colors">
                    <Icons.Menu size={24} className="text-white" />
                </button>
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-md-primary to-md-secondary flex items-center justify-center">
                        <span className="font-bold text-black text-xs">AI</span>
                    </div>
                    <span className="font-bold text-xl tracking-tight">Shahid_AI</span>
                </div>
            </div>
            <div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-xs font-bold text-gray-300 border border-gray-600">
                U
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-[#1e1e1e] border-t border-gray-800 pb-safe">
        <div className="flex justify-around items-center h-16 max-w-md mx-auto">
            <button 
                onClick={() => setCurrentView(AppView.HOME)}
                className={`flex flex-col items-center gap-1 p-2 w-full transition-colors ${currentView === AppView.HOME ? 'text-md-primary' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <div className={`p-1 rounded-full ${currentView === AppView.HOME ? 'bg-md-primary/10' : ''}`}>
                    <Icons.Home size={22} />
                </div>
                <span className="text-[10px] font-medium">Home</span>
            </button>
            <button 
                onClick={() => setCurrentView(AppView.HISTORY)}
                className={`flex flex-col items-center gap-1 p-2 w-full transition-colors ${currentView === AppView.HISTORY ? 'text-md-primary' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <div className={`p-1 rounded-full ${currentView === AppView.HISTORY ? 'bg-md-primary/10' : ''}`}>
                    <Icons.History size={22} />
                </div>
                <span className="text-[10px] font-medium">History</span>
            </button>
            <button 
                onClick={() => setCurrentView(AppView.SETTINGS)}
                className={`flex flex-col items-center gap-1 p-2 w-full transition-colors ${currentView === AppView.SETTINGS ? 'text-md-primary' : 'text-gray-500 hover:text-gray-300'}`}
            >
                 <div className={`p-1 rounded-full ${currentView === AppView.SETTINGS ? 'bg-md-primary/10' : ''}`}>
                    <Icons.Settings size={22} />
                </div>
                <span className="text-[10px] font-medium">Settings</span>
            </button>
        </div>
      </nav>
    </div>
  );
};

export default App;

