import React, { useEffect } from 'react';
import { Icons } from './Icons';

interface ToastProps {
  message: string;
  type?: 'success' | 'error' | 'info';
  onClose: () => void;
}

export const Toast: React.FC<ToastProps> = ({ message, type = 'info', onClose }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onClose();
    }, 3000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const bgColors = {
    success: 'bg-md-primary/10 border-md-primary text-md-primary',
    error: 'bg-md-error/10 border-md-error text-md-error',
    info: 'bg-md-secondary/10 border-md-secondary text-md-secondary'
  };

  return (
    <div className={`fixed top-4 left-1/2 transform -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full border backdrop-blur-md shadow-2xl animate-fade-in-up ${bgColors[type]}`}>
      {type === 'success' && <Icons.Check size={18} />}
      {type === 'error' && <Icons.Zap size={18} />}
      {type === 'info' && <Icons.Info size={18} />}
      <span className="font-medium text-sm">{message}</span>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GeneratedFile } from '../types';
import { Icons } from './Icons';

// Declare global Prism object
declare const Prism: any;

interface CodeCardProps {
  file: GeneratedFile;
  onCopy: (text: string) => void;
}

export const CodeCard: React.FC<CodeCardProps> = ({ file, onCopy }) => {
  const [copied, setCopied] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    // Trigger syntax highlighting when content changes or view changes
    if (typeof Prism !== 'undefined') {
      Prism.highlightAll();
    }
  }, [file.content, isFullscreen]);

  const handleCopy = () => {
    onCopy(file.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getLanguageClass = (filename: string, lang: string) => {
    if (lang === 'typescript' || filename.endsWith('.ts') || filename.endsWith('.tsx')) return 'language-tsx';
    if (lang === 'javascript' || filename.endsWith('.js') || filename.endsWith('.jsx')) return 'language-jsx';
    if (lang === 'python' || filename.endsWith('.py')) return 'language-python';
    if (lang === 'css') return 'language-css';
    if (lang === 'json') return 'language-json';
    return 'language-javascript'; // Default
  };

  const codeBlock = (
    <pre className={`text-sm font-mono leading-relaxed bg-[#0e0e0e] text-gray-300 p-5 overflow-x-auto ${isFullscreen ? 'h-full' : 'max-h-[400px]'}`}>
      <code className={getLanguageClass(file.path, file.language)}>{file.content}</code>
    </pre>
  );

  if (isFullscreen) {
    return (
      <div className="fixed inset-0 z-[60] bg-[#121212] flex flex-col animate-fade-in-up">
        <div className="flex items-center justify-between p-4 border-b border-gray-800 bg-md-surfaceVariant">
            <div className="flex items-center gap-2">
                 <Icons.FileCode size={20} className="text-md-secondary" />
                 <span className="font-mono text-lg font-bold">{file.path}</span>
            </div>
            <div className="flex gap-2">
                <button onClick={handleCopy} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    {copied ? <Icons.Check size={20} className="text-md-primary"/> : <Icons.Copy size={20} />}
                </button>
                <button onClick={() => setIsFullscreen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-400 hover:text-white">
                    <Icons.X size={24} />
                </button>
            </div>
        </div>
        <div className="flex-1 overflow-auto bg-[#0e0e0e] p-4">
