  'vanilla': 'Use vanilla HTML5, CSS3, and modern JavaScript (ES6+).'
};

export const generateProjectBlueprint = async (projectName: string, stackId: string): Promise<ProjectBlueprint> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const techStackInstruction = stackPrompts[stackId] || stackPrompts['react-node'];

  const systemInstruction = `You are a world-class senior software architect. 
  Your goal is to provide a COMPREHENSIVE, PRODUCTION-READY code blueprint.

  CRITICAL RULES:
  1. Do NOT use placeholders, TODOs, or comments like "// code goes here". Write the FULL, WORKING implementation.
  2. Provide a substantial number of files (aim for 8-15 files) to form a complete working prototype.
  3. Include ALL necessary configuration files (e.g., package.json, platformio.ini, tsconfig.json).
  4. Ensure the code is clean, modular, and follows best practices for the chosen stack (e.g., separate headers/implementation for C++).
  5. Include a robust README.md with setup and wiring instructions if hardware is involved.

  When asked for a project name, generate:
  1. A detailed technical description.
  2. A complete visual folder structure tree.
  3. The actual code content for the files.

  Return strictly JSON data adhering to the schema.`;

  const prompt = `Act as a senior developer. For the project named "${projectName}", provide the complete folder structure and EXTENSIVE, DETAILED code for the application.

  Technical Constraints: ${techStackInstruction}

  REQUIREMENTS:
  - The application must be functional, not just a shell.
  - Include distinct components, services, styles, and utility functions.
  - Ensure styling (Tailwind/CSS) is fully implemented in the components.
  - If it is an Embedded/ESP32 project: Provide wiring details in comments, handle Wi-Fi connection securely, and structure the code with clear setup() and loop() functions.

  Generate a high-quality, comprehensive blueprint.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: blueprintSchema,
        thinkingConfig: { thinkingBudget: 4096 }
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from Gemini.");
    }

    const data = JSON.parse(text);

    return {
      projectName,
      description: data.description,
      structure: data.structure,
      files: data.files,
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const enhanceProjectBlueprint = async (files: GeneratedFile[], instructions: string, projectName: string): Promise<ProjectBlueprint> => {
    if (!apiKey) {
        throw new Error("API Key is missing.");
    }

    const ai = new GoogleGenAI({ apiKey });

    // Prepare context from files
    // Limit to reasonable size to prevent token overflow, though Gemini 2.0 has a large context.
    const fileContext = files.map(f => `### File: ${f.path}\n\`\`\`${f.language}\n${f.content}\n\`\`\``).join('\n\n');

    const systemInstruction = `You are an expert Code Reviewer and Architect.
    Your task is to analyze an existing codebase, apply requested enhancements, fix bugs, and return the IMPROVED full version of the project.

    CRITICAL RULES:
    1. Return the FULL project structure, including unchanged files (unless they are irrelevant).
    2. Apply the user's specific instructions for enhancement.
    3. If no specific instructions are given, apply general best practices: clean code, better comments, improved error handling, and modern patterns.
    4. Ensure the returned JSON adheres to the schema.
    `;

    const prompt = `I have an existing project named "${projectName}".

    User Instructions for Enhancement: "${instructions || "General code quality improvement, optimization, and bug fixing."}"

    Current Project Files:
    ${fileContext}

    Please return the enhanced project blueprint.`;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
                responseMimeType: "application/json",
                responseSchema: blueprintSchema,
                thinkingConfig: { thinkingBudget: 4096 }
            },
        });

        const text = response.text;
        if (!text) throw new Error("No response from Gemini.");

        const data = JSON.parse(text);

        return {
            projectName,
            description: data.description,
            structure: data.structure,
            files: data.files
        };

    } catch (error) {
        console.error("Enhancement Error:", error);
        throw error;
    }
};

import React, { useState, useRef } from 'react';
import { Icons } from './Icons';
import { GeneratedFile } from '../types';
import { readProjectZip } from '../utils/zipUtils';

interface FloatingInputProps {
  onSubmit: (projectName: string, stack: string) => void;
  onEnhance: (files: GeneratedFile[], instructions: string, projectName: string) => void;
  isLoading: boolean;
}

const TECH_STACKS = [
  { id: 'react-node', label: 'React + Node', icon: '⚡' },
  { id: 'esp32', label: 'ESP32 / IoT', icon: '🤖' },
  { id: 'nextjs', label: 'Next.js', icon: '▲' },
  { id: 'python-fastapi', label: 'Python FastAPI', icon: '🐍' },
  { id: 'vue-firebase', label: 'Vue + Firebase', icon: '🔥' },
  { id: 'flutter', label: 'Flutter', icon: '💙' },
  { id: 'vanilla', label: 'HTML/CSS/JS', icon: '🌐' },
];

export const FloatingInput: React.FC<FloatingInputProps> = ({ onSubmit, onEnhance, isLoading }) => {
  const [mode, setMode] = useState<'create' | 'enhance'>('create');

  // Create Mode State
  const [value, setValue] = useState('');
  const [showOptions, setShowOptions] = useState(false);
  const [selectedStack, setSelectedStack] = useState(TECH_STACKS[0].id);

  // Enhance Mode State
  const [uploadedFiles, setUploadedFiles] = useState<GeneratedFile[]>([]);
  const [uploadName, setUploadName] = useState<string>('');
  const [instructions, setInstructions] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleGenerateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (value.trim()) {
      onSubmit(value, selectedStack);
    }
  };

  const handleEnhanceSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (uploadedFiles.length > 0) {
          onEnhance(uploadedFiles, instructions, uploadName || 'Enhanced Project');
      }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      try {
          const { files, guessedName } = await readProjectZip(file);
          setUploadedFiles(files);
          setUploadName(guessedName);
      } catch (error) {
          console.error("Error reading zip", error);
          alert("Failed to read zip file. Ensure it contains text files.");
      }
  };

  return (
    <div className="w-full max-w-lg mx-auto relative z-20">

      {/* Mode Switcher */}
      <div className="flex justify-center mb-6 gap-2">
        <button
            onClick={() => setMode('create')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-all ${
                mode === 'create' 
                ? 'bg-md-primary text-black shadow-[0_0_15px_rgba(3,218,198,0.3)]' 
                : 'bg-md-surfaceVariant text-gray-400 hover:text-white border border-gray-700'
            }`}
        >
            <span className="flex items-center gap-2"><Icons.Sparkles size={16} /> New Design</span>
        </button>
        <button
            onClick={() => setMode('enhance')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-all ${
                mode === 'enhance' 
                ? 'bg-md-secondary text-black shadow-[0_0_15px_rgba(187,134,252,0.3)]' 
                : 'bg-md-surfaceVariant text-gray-400 hover:text-white border border-gray-700'
            }`}
        >
            <span className="flex items-center gap-2"><Icons.UploadCloud size={16} /> Enhance</span>
        </button>
      </div>

      {mode === 'create' ? (
        // CREATE FORM
        <form onSubmit={handleGenerateSubmit} className="relative flex flex-col gap-4 animate-fade-in-up">
            <div className="bg-md-surfaceVariant rounded-[20px] shadow-2xl border border-gray-700 p-2 transition-all duration-300 focus-within:border-md-primary focus-within:ring-1 focus-within:ring-md-primary/50">
                <div className="relative">
                    <input
                    type="text"
                    id="projectName"
                    className="block w-full px-4 pt-6 pb-2 text-lg bg-transparent appearance-none text-md-onSurface focus:outline-none peer placeholder-transparent"
                    placeholder="Project Name"
                    value={value}
                    onChange={(e) => setValue(e.target.value)}
                    disabled={isLoading}
                    autoComplete="off"
                    />
                    <label
                    htmlFor="projectName"
                    className="absolute text-md text-gray-400 duration-300 transform -translate-y-3 scale-75 top-4 z-10 origin-[0] left-4 peer-placeholder-shown:scale-100 peer-placeholder-shown:translate-y-0 peer-focus:scale-75 peer-focus:-translate-y-3 peer-focus:text-md-primary"
                    >
                    Project Name
                    </label>

                    <button
                        type="button"
                        onClick={() => setShowOptions(!showOptions)}
                        className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full transition-colors ${showOptions ? 'bg-md-primary text-black' : 'hover:bg-white/10 text-gray-400'}`}
                        title="Select Tech Stack"
                    >
                        <Icons.SlidersHorizontal size={20} />
                    </button>
                </div>

                <div className={`overflow-hidden transition-all duration-300 ease-in-out ${showOptions ? 'max-h-40 opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
                    <div className="px-2 pb-2">
                        <p className="text-xs text-gray-500 mb-2 font-medium uppercase tracking-wider">Target Architecture</p>
                        <div className="flex flex-wrap gap-2">
                            {TECH_STACKS.map(stack => (
                                <button
                                    key={stack.id}
                                    type="button"
                                    onClick={() => setSelectedStack(stack.id)}
                                    className={`text-xs px-3 py-1.5 rounded-full border transition-all flex items-center gap-1.5 ${
                                        selectedStack === stack.id 
                                        ? 'bg-md-primary/20 border-md-primary text-md-primary' 
                                        : 'border-gray-600 text-gray-400 hover:border-gray-500'
                                    }`}
                                >
                                    <span>{stack.icon}</span>
                                    {stack.label}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <button
                type="submit"
                disabled={isLoading || !value.trim()}
                className={`
                    mx-auto
                    flex items-center justify-center gap-2 
                    py-4 px-10 rounded-[24px] 
                    bg-gradient-to-r from-md-primary to-md-primaryVariant
                    text-[#121212] font-bold text-lg tracking-wide shadow-lg shadow-md-primary/20
                    transition-all duration-300 transform 
                    ${isLoading ? 'opacity-90 cursor-not-allowed scale-95' : 'hover:scale-105 hover:shadow-xl active:scale-95'}
                `}
            >
                {isLoading ? (
                    <>
                    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-[#121212]"></div>
                    <span className="animate-pulse">Deep Architecting...</span>
                    </>
                ) : (
                    <>
                    <Icons.Sparkles size={20} />
                    <span>Generate Blueprint</span>
                    </>
                )}
            </button>
        </form>
      ) : (
        // ENHANCE FORM
        <form onSubmit={handleEnhanceSubmit} className="relative flex flex-col gap-4 animate-fade-in-up">
            <div className="bg-md-surfaceVariant rounded-[20px] shadow-2xl border border-gray-700 p-4 transition-all duration-300">
                <input 
                    type="file" 
                    ref={fileInputRef}
                    accept=".zip"
                    onChange={handleFileUpload}
                    className="hidden"
                />

                {uploadedFiles.length === 0 ? (
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="border-2 border-dashed border-gray-600 rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer hover:border-md-secondary hover:bg-white/5 transition-all text-gray-400 hover:text-white"
                    >
                        <Icons.UploadCloud size={32} className="mb-2" />
                        <span className="font-medium">Upload Project (.zip)</span>
                        <span className="text-xs text-gray-500 mt-1">Text files only, max 5MB</span>
                    </div>
                ) : (
                     <div className="bg-md-secondary/10 border border-md-secondary rounded-xl p-4 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Icons.FileCode className="text-md-secondary" />
                            <div>
                                <div className="font-bold text-white text-sm">{uploadName}.zip</div>
                                <div className="text-xs text-gray-400">{uploadedFiles.length} files extracted</div>
                            </div>
                        </div>
                        <button 
                            type="button" 
                            onClick={() => { setUploadedFiles([]); setUploadName(''); }}
                            className="p-1 hover:bg-white/10 rounded-full"
                        >
                            <Icons.X size={18} className="text-gray-400 hover:text-white" />
                        </button>
                     </div>
                )}

                <div className="mt-4">
                     <label className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2 block">Instructions (Optional)</label>
                     <textarea 
                        className="w-full bg-[#121212] border border-gray-700 rounded-lg p-3 text-sm text-gray-200 focus:border-md-secondary focus:outline-none resize-none h-24"
                        placeholder="e.g. Fix bugs, add TypeScript types, improve CSS..."
                        value={instructions}
                        onChange={(e) => setInstructions(e.target.value)}
                     />
                </div>
            </div>

            <button
                type="submit"
                disabled={isLoading || uploadedFiles.length === 0}
                className={`
                    mx-auto
                    flex items-center justify-center gap-2 
                    py-4 px-10 rounded-[24px] 
                    bg-gradient-to-r from-md-secondary to-md-secondary/70
                    text-[#121212] font-bold text-lg tracking-wide shadow-lg shadow-md-secondary/20
                    transition-all duration-300 transform 
                    ${isLoading || uploadedFiles.length === 0 ? 'opacity-70 cursor-not-allowed scale-95' : 'hover:scale-105 hover:shadow-xl active:scale-95'}
                `}
            >
                {isLoading ? (
                    <>
                    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-[#121212]"></div>
                    <span className="animate-pulse">Analyzing Code...</span>
                    </>
                ) : (
                    <>
                    <Icons.FileUp size={20} />
                    <span>Analyze & Enhance</span>
                    </>
                )}
            </button>
        </form>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Icons } from './components/Icons';
import { FloatingInput } from './components/FloatingInput';
import { CodeCard } from './components/CodeCard';
import { Toast } from './components/Toast';
import { generateProjectBlueprint, enhanceProjectBlueprint } from './services/geminiService';
import { downloadProjectZip } from './utils/zipUtils';
import { ProjectBlueprint, AppView, HistoryItem, GeneratedFile } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [blueprint, setBlueprint] = useState<ProjectBlueprint | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // Load history from local storage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('shahid_ai_history');
    if (savedHistory) {
        try {
            setHistory(JSON.parse(savedHistory));
        } catch (e) {
            console.error("Failed to parse history", e);
        }
    }
  }, []);

  // Save history when it changes
  useEffect(() => {
    localStorage.setItem('shahid_ai_history', JSON.stringify(history));
  }, [history]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToast({ message, type });
  };

  const handleCopy = (text: string) => {
      navigator.clipboard.writeText(text);
      showToast('Copied to clipboard', 'success');
  };

  const handleGenerate = async (projectName: string, stackId: string) => {
    setIsLoading(true);
    setError(null);
    setBlueprint(null);
    try {
      const result = await generateProjectBlueprint(projectName, stackId);
      handleSuccess(result, 'Blueprint generated successfully');
    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEnhance = async (files: GeneratedFile[], instructions: string, projectName: string) => {
      setIsLoading(true);
      setError(null);
      setBlueprint(null);
      try {
          const result = await enhanceProjectBlueprint(files, instructions, projectName);
          handleSuccess(result, 'Project enhanced successfully');
      } catch (err) {
          handleError(err);
      } finally {
          setIsLoading(false);
      }
  };

  const handleSuccess = (result: ProjectBlueprint, msg: string) => {
      setBlueprint(result);
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        projectName: result.projectName,
        blueprint: result
      };
      setHistory(prev => [newHistoryItem, ...prev]);
      showToast(msg, 'success');
  };

  const handleError = (err: unknown) => {
      const msg = err instanceof Error ? err.message : "An unexpected error occurred.";
      setError(msg);
      showToast(msg, 'error');
  };

  const handleDownload = () => {
    if (blueprint) {
      downloadProjectZip(blueprint.projectName, blueprint.files);
      showToast('Downloading ZIP...', 'info');
    }
  };

  const deleteHistoryItem = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setHistory(prev => prev.filter(item => item.id !== id));
      showToast('History item deleted', 'info');
  };

  const renderContent = () => {
    if (currentView === AppView.HISTORY) {
        return (
            <div className="p-4 pb-24 max-w-3xl mx-auto animate-fade-in-up">
                 <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-md-primary">Project History</h2>
                    <span className="text-gray-500 text-sm">{history.length} projects</span>
                 </div>

                 {history.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-20 text-gray-600">
                        <Icons.History size={48} className="mb-4 opacity-50" />
                        <p>No generated blueprints yet.</p>
                    </div>
                 ) : (
                    <div className="space-y-4">
                        {history.map(item => (
                            <div 
                                key={item.id} 
                                onClick={() => {
                                    setBlueprint(item.blueprint);
                                    setCurrentView(AppView.HOME);
                                }}
                                className="bg-md-surfaceVariant hover:bg-[#383838] p-5 rounded-xl border border-gray-700 flex justify-between items-center cursor-pointer transition-all group"
                            >
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 rounded-full bg-md-primary/10 flex items-center justify-center text-md-primary">
                                        <Icons.Code size={20} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-lg text-white group-hover:text-md-primary transition-colors">{item.projectName}</h3>
                                        <p className="text-xs text-gray-400">{new Date(item.timestamp).toLocaleDateString()} at {new Date(item.timestamp).toLocaleTimeString()}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <button 
                                        onClick={(e) => deleteHistoryItem(item.id, e)}
                                        className="text-gray-500 hover:text-md-error hover:bg-md-error/10 p-2 rounded-lg transition-colors"
                                    >
                                        <Icons.Trash2 size={18} />
                                    </button>
                                    <Icons.ChevronRight size={20} className="text-gray-600 group-hover:text-white" />
                                </div>
                            </div>
                        ))}
                    </div>
                 )}
            </div>
        )
    }

