        {/* Loading Skeleton */}
        {isLoading && !blueprint && (
            <div className="mt-12 space-y-6 animate-pulse-slow max-w-3xl mx-auto">
                <div className="h-40 bg-md-surfaceVariant rounded-2xl w-full"></div>
