// Declare global Prism object
declare const Prism: any;

interface CodeCardProps {
  file: GeneratedFile;
  onCopy: (text: string) => void;
  settings: AppSettings;
}

export const CodeCard: React.FC<CodeCardProps> = ({ file, onCopy, settings }) => {
  const [copied, setCopied] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    // Trigger syntax highlighting when content changes or view changes
    // Only if syntaxHighlight is enabled
    if (typeof Prism !== 'undefined' && settings.syntaxHighlight) {
      Prism.highlightAll();
    }
  }, [file.content, isFullscreen, settings.syntaxHighlight]);

  const handleCopy = () => {
    onCopy(file.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getLanguageClass = (filename: string, lang: string) => {
    if (!settings.syntaxHighlight) return 'language-none';

    const ext = filename.split('.').pop()?.toLowerCase();

    if (lang === 'typescript' || ext === 'ts' || ext === 'tsx') return 'language-tsx';
    if (lang === 'javascript' || ext === 'js' || ext === 'jsx') return 'language-jsx';
    if (lang === 'python' || ext === 'py') return 'language-python';
    if (lang === 'css' || ext === 'css') return 'language-css';
    if (lang === 'json' || ext === 'json') return 'language-json';
    if (lang === 'cpp' || ext === 'cpp' || ext === 'c' || ext === 'h' || ext === 'hpp' || ext === 'ino') return 'language-cpp';
    if (ext === 'ini') return 'language-ini';
    return 'language-javascript'; // Default
  };

  const codeStyle = {
    fontSize: `${settings.editorFontSize}px`,
  };

  const codeBlock = (
    <pre 
        className={`font-mono leading-relaxed bg-[#0e0e0e] text-gray-300 p-5 overflow-x-auto ${isFullscreen ? 'h-full' : 'max-h-[400px]'} ${settings.wordWrap ? 'whitespace-pre-wrap' : 'whitespace-pre'}`}
        style={codeStyle}
    >
      <code className={getLanguageClass(file.path, file.language)}>{file.content}</code>
    </pre>
  );

  if (isFullscreen) {
    return (
      <div className="fixed inset-0 z-[60] bg-[#121212] flex flex-col animate-fade-in-up">
        <div className="flex items-center justify-between p-4 border-b border-gray-800 bg-md-surfaceVariant">
            <div className="flex items-center gap-2">
                 <Icons.FileCode size={20} className="text-md-secondary" />
                 <span className="font-mono text-lg font-bold">{file.path}</span>
            </div>
            <div className="flex gap-2">
                <button onClick={handleCopy} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    {copied ? <Icons.Check size={20} className="text-md-primary"/> : <Icons.Copy size={20} />}
                </button>
                <button onClick={() => setIsFullscreen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-400 hover:text-white">
                    <Icons.X size={24} />
                </button>
            </div>
        </div>
        <div className="flex-1 overflow-auto bg-[#0e0e0e] p-4">
            {codeBlock}
        </div>
      </div>
    );
  }

  return (
    <div className="bg-md-surfaceVariant rounded-[24px] overflow-hidden shadow-lg border border-gray-800 mb-6 transition-all duration-300 hover:shadow-2xl hover:border-md-primary/30 group">
      <div className="bg-[#1e1e1e] px-5 py-3 flex justify-between items-center border-b border-gray-800">
        <div className="flex items-center gap-2">
            <Icons.FileCode size={18} className="text-md-secondary" />
            <span className="font-mono text-sm text-md-onSurface opacity-80">{file.path}</span>
        </div>
        <div className="flex items-center gap-1">
            <button 
                onClick={() => setIsFullscreen(true)}
                className="p-2 rounded-full hover:bg-white/5 transition-colors text-gray-400 hover:text-white"
                title="Expand"
            >
                <Icons.Maximize2 size={16} />
            </button>
            <button 
                onClick={handleCopy}
                className="p-2 rounded-full hover:bg-white/5 transition-colors text-md-primary"
                title="Copy code"
            >
                {copied ? <Icons.Check size={18} /> : <Icons.Copy size={18} />}
            </button>
        </div>
      </div>
      <div className="relative">
        {codeBlock}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Icons } from './components/Icons';
import { FloatingInput } from './components/FloatingInput';
import { CodeCard } from './components/CodeCard';
import { Toast } from './components/Toast';
import { generateProjectBlueprint, enhanceProjectBlueprint } from './services/geminiService';
import { downloadProjectZip } from './utils/zipUtils';
import { ProjectBlueprint, AppView, HistoryItem, GeneratedFile, AppSettings } from './types';

// Initial Settings Default
const DEFAULT_SETTINGS: AppSettings = {
  editorFontSize: 14,
  wordWrap: false,
  syntaxHighlight: true,
  autoSave: true,
  showHidden: false
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [blueprint, setBlueprint] = useState<ProjectBlueprint | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // Settings State
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);

  // Load history & settings on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('shahid_ai_history');
    if (savedHistory) {
        try {
            setHistory(JSON.parse(savedHistory));
        } catch (e) {
            console.error("Failed to parse history", e);
        }
    }

    const savedSettings = localStorage.getItem('shahid_ai_settings');
    if (savedSettings) {
      try {
        setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(savedSettings) });
      } catch (e) {
        console.error("Failed to parse settings", e);
      }
    }
  }, []);

  // Save history when it changes (if Auto Save is on)
  useEffect(() => {
    if (settings.autoSave) {
      localStorage.setItem('shahid_ai_history', JSON.stringify(history));
    }
  }, [history, settings.autoSave]);

  // Save settings when they change
  useEffect(() => {
    localStorage.setItem('shahid_ai_settings', JSON.stringify(settings));
  }, [settings]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToast({ message, type });
  };

  const handleCopy = (text: string) => {
      navigator.clipboard.writeText(text);
      showToast('Copied to clipboard', 'success');
  };

  const handleGenerate = async (projectName: string, stackId: string) => {
    setIsLoading(true);
    setError(null);
    setBlueprint(null);
    try {
      const result = await generateProjectBlueprint(projectName, stackId);
      handleSuccess(result, 'Blueprint generated successfully');
    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEnhance = async (files: GeneratedFile[], instructions: string, projectName: string) => {
      setIsLoading(true);
      setError(null);
      setBlueprint(null);
      try {
          const result = await enhanceProjectBlueprint(files, instructions, projectName);
          handleSuccess(result, 'Project enhanced successfully');
      } catch (err) {
          handleError(err);
      } finally {
          setIsLoading(false);
      }
  };

  const handleSuccess = (result: ProjectBlueprint, msg: string) => {
      setBlueprint(result);
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        projectName: result.projectName,
        blueprint: result
      };
      setHistory(prev => [newHistoryItem, ...prev]);
      showToast(msg, 'success');
  };

  const handleError = (err: unknown) => {
      const msg = err instanceof Error ? err.message : "An unexpected error occurred.";
      setError(msg);
      showToast(msg, 'error');
  };

  const handleDownload = () => {
    if (blueprint) {
      downloadProjectZip(blueprint.projectName, blueprint.files);
      showToast('Downloading ZIP...', 'info');
    }
  };

  const deleteHistoryItem = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setHistory(prev => prev.filter(item => item.id !== id));
      showToast('History item deleted', 'info');
  };

  const updateSetting = <K extends keyof AppSettings>(key: K, value: AppSettings[K]) => {
    setSettings(prev => ({ ...prev, [key]: value }));
  };

  const renderContent = () => {
    if (currentView === AppView.HISTORY) {
        return (
            <div className="p-4 pb-24 max-w-3xl mx-auto animate-fade-in-up">
                 <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-md-primary">Project History</h2>
                    <span className="text-gray-500 text-sm">{history.length} projects</span>
                 </div>

                 {history.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-20 text-gray-600">
                        <Icons.History size={48} className="mb-4 opacity-50" />
                        <p>No generated blueprints yet.</p>
                    </div>
                 ) : (
                    <div className="space-y-4">
                        {history.map(item => (
                            <div 
                                key={item.id} 
                                onClick={() => {
                                    setBlueprint(item.blueprint);
                                    setCurrentView(AppView.HOME);
                                }}
                                className="bg-md-surfaceVariant hover:bg-[#383838] p-5 rounded-xl border border-gray-700 flex justify-between items-center cursor-pointer transition-all group"
                            >
                                <div className="flex items-center gap-4">
