import JSZip from 'jszip';
import saveAs from 'file-saver';
import { GeneratedFile } from '../types';

export const downloadProjectZip = async (projectName: string, files: GeneratedFile[]) => {
  const zip = new JSZip();

  files.forEach((file) => {
    // Remove leading slash if present to avoid empty root folder issues
    const path = file.path.startsWith('/') ? file.path.slice(1) : file.path;
    zip.file(path, file.content);
  });

  const content = await zip.generateAsync({ type: 'blob' });
  saveAs(content, `${projectName}-blueprint.zip`);
};

export const readProjectZip = async (file: File): Promise<{ files: GeneratedFile[]; guessedName: string }> => {
  const zip = new JSZip();
  const loadedZip = await zip.loadAsync(file);
  const files: GeneratedFile[] = [];

  // Try to guess project name from the root folder if possible, otherwise filename
  let guessedName = file.name.replace('.zip', '');

  for (const [relativePath, zipEntry] of Object.entries(loadedZip.files)) {
    const entry = zipEntry as any;

    if (entry.dir) continue;

    // Filter out binary/unwanted files
    if (relativePath.includes('node_modules') || 
        relativePath.includes('.git') || 
        relativePath.includes('dist') || 
        relativePath.includes('build') ||
        relativePath.includes('.next') ||
        relativePath.includes('__pycache__') ||
        relativePath.includes('.DS_Store')) continue;

    // Check extension for text files
    const validExtensions = [
        '.js', '.jsx', '.ts', '.tsx', 
        '.html', '.css', '.scss', '.sass', '.less',
        '.json', '.xml', '.yaml', '.yml', '.toml',
        '.py', '.rb', '.go', '.rs', '.java', '.kt', '.swift', '.php', 
        '.c', '.cpp', '.h', '.hpp', '.ino', '.cs',
        '.md', '.txt', '.sh', '.bat',
        '.vue', '.svelte', '.astro',
        '.ini', '.env.example', '.gitignore'
    ];

    const ext = '.' + relativePath.split('.').pop()?.toLowerCase();

    const isExactMatch = validExtensions.includes(ext);
    const isSpecialFile = relativePath.endsWith('Makefile') || relativePath.endsWith('Dockerfile') || relativePath.endsWith('Jenkinsfile');

    if (!isExactMatch && !isSpecialFile) {
        continue;
    }

    try {
      const content = await entry.async('string');
      // Skip empty files or files that are likely binary but slipped through
      if (!content || content.includes('\0')) continue;

      files.push({
        path: relativePath,
        content: content,
        language: getLanguageFromExt(ext)
      });
    } catch (e) {
      console.warn(`Skipping binary or unreadable file: ${relativePath}`);
    }
  }

  return { files, guessedName };
};

const getLanguageFromExt = (ext: string): string => {
    if (ext === '.ts' || ext === '.tsx') return 'typescript';
    if (ext === '.js' || ext === '.jsx') return 'javascript';
    if (ext === '.py') return 'python';
    if (['.css', '.scss', '.sass', '.less'].includes(ext)) return 'css';
    if (ext === '.json') return 'json';
    if (ext === '.html') return 'html';
    if (['.cpp', '.c', '.h', '.hpp', '.ino', '.cs', '.java'].includes(ext)) return 'cpp';
    if (['.yaml', '.yml', '.toml', '.ini'].includes(ext)) return 'ini';
    if (ext === '.xml') return 'xml';
    if (ext === '.md') return 'markdown';
    if (ext === '.sh') return 'bash';
    return 'plaintext';
};

import React, { useState, useEffect } from 'react';
import { Icons } from './components/Icons';
import { FloatingInput } from './components/FloatingInput';
import { CodeCard } from './components/CodeCard';
import { Toast } from './components/Toast';
import { generateProjectBlueprint, enhanceProjectBlueprint } from './services/geminiService';
import { downloadProjectZip } from './utils/zipUtils';
import { ProjectBlueprint, AppView, HistoryItem, GeneratedFile, AppSettings } from './types';

// Initial Settings Default
const DEFAULT_SETTINGS: AppSettings = {
  editorFontSize: 14,
  wordWrap: false,
  syntaxHighlight: true,
  autoSave: true,
  showHidden: false,
  useCustomApi: false,
  openRouterApiKey: '',
  customModelId: 'openrouter/free'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [blueprint, setBlueprint] = useState<ProjectBlueprint | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // Settings State
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);

  // Load history & settings on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('shahid_ai_history');
    if (savedHistory) {
        try {
            setHistory(JSON.parse(savedHistory));
        } catch (e) {
            console.error("Failed to parse history", e);
        }
    }

    const savedSettings = localStorage.getItem('shahid_ai_settings');
    if (savedSettings) {
      try {
        setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(savedSettings) });
      } catch (e) {
        console.error("Failed to parse settings", e);
      }
    }
  }, []);

  // Save history when it changes (if Auto Save is on)
  useEffect(() => {
    if (settings.autoSave) {
      localStorage.setItem('shahid_ai_history', JSON.stringify(history));
    }
  }, [history, settings.autoSave]);

  // Save settings when they change
  useEffect(() => {
    localStorage.setItem('shahid_ai_settings', JSON.stringify(settings));
  }, [settings]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToast({ message, type });
  };

  const handleCopy = (text: string) => {
      navigator.clipboard.writeText(text);
      showToast('Copied to clipboard', 'success');
  };

  const handleGenerate = async (projectName: string, stackId: string) => {
    setIsLoading(true);
    setError(null);
    setBlueprint(null);
    try {
      const result = await generateProjectBlueprint(projectName, stackId, settings);
      handleSuccess(result, 'Blueprint generated successfully');
    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEnhance = async (files: GeneratedFile[], instructions: string, projectName: string) => {
      setIsLoading(true);
      setError(null);
      setBlueprint(null);
      try {
          const result = await enhanceProjectBlueprint(files, instructions, projectName, settings);
          handleSuccess(result, 'Project enhanced successfully');
      } catch (err) {
          handleError(err);
      } finally {
          setIsLoading(false);
      }
  };

  const handleSuccess = (result: ProjectBlueprint, msg: string) => {
      setBlueprint(result);
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        projectName: result.projectName,
        blueprint: result
      };
      setHistory(prev => [newHistoryItem, ...prev]);
      showToast(msg, 'success');
  };

  const handleError = (err: unknown) => {
      const msg = err instanceof Error ? err.message : "An unexpected error occurred.";
      setError(msg);
      showToast(msg, 'error');
  };

  const handleDownload = () => {
    if (blueprint) {
      downloadProjectZip(blueprint.projectName, blueprint.files);
      showToast('Downloading ZIP...', 'info');
    }
  };

  const deleteHistoryItem = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setHistory(prev => prev.filter(item => item.id !== id));
      showToast('History item deleted', 'info');
  };

  const updateSetting = <K extends keyof AppSettings>(key: K, value: AppSettings[K]) => {
    setSettings(prev => ({ ...prev, [key]: value }));
  };

  const renderContent = () => {
    if (currentView === AppView.HISTORY) {
        return (
            <div className="p-4 pb-24 max-w-3xl mx-auto animate-fade-in-up">
                 <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-md-primary">Project History</h2>
                    <span className="text-gray-500 text-sm">{history.length} projects</span>
                 </div>

                 {history.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-20 text-gray-600">
                        <Icons.History size={48} className="mb-4 opacity-50" />
                        <p>No generated blueprints yet.</p>
                    </div>
                 ) : (
                    <div className="space-y-4">
                        {history.map(item => (
                            <div 
                                key={item.id} 
                                onClick={() => {
                                    setBlueprint(item.blueprint);
                                    setCurrentView(AppView.HOME);
                                }}
                                className="bg-md-surfaceVariant hover:bg-[#383838] p-5 rounded-xl border border-gray-700 flex justify-between items-center cursor-pointer transition-all group"
                            >
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 rounded-full bg-md-primary/10 flex items-center justify-center text-md-primary">
                                        <Icons.Code size={20} />
